Class Validator Extends %RegisteredObject
{
    /// Validate email format and return status
    ClassMethod ValidateEmail(email As %String) As %Status
    {
        // Check for @ symbol
        If (email '[ "@") {
            // BUGGY: Should return error status, not just quit
            Quit
        }

        // Check for domain
        Set domain = $PIECE(email, "@", 2)
        If (domain = "") {
            Quit
        }

        Quit $$$OK
    }
}

