Class TestValidator Extends %RegisteredObject
{
    ClassMethod TestValidateEmail()
    {
        // Valid email should return OK
        Set sc = ##class(Validator).ValidateEmail("test@example.com")
        If $$$ISERR(sc) {
            Throw ##class(%Exception.General).%New("Valid email should return OK status")
        }

        // Invalid email (no @) should return error status
        Set sc = ##class(Validator).ValidateEmail("invalid-email")
        If '$$$ISERR(sc) {
            Throw ##class(%Exception.General).%New("Email without @ should return error status")
        }

        // Invalid email (no domain) should return error
        Set sc = ##class(Validator).ValidateEmail("test@")
        If '$$$ISERR(sc) {
            Throw ##class(%Exception.General).%New("Email without domain should return error status")
        }
    }
}
